import DOM from "./dom.js";
import Dragable from "./drag.js";
import QueryHelper from "./query-helper.js";
import { groupBy } from "./utils.js";

export default class Mkr {
    constructor( state , api ) {
        this._dom = new DOM();
        this._query = new QueryHelper();
        this._mkr = this._query._mkr;

        this._state = state;
        this._api = api;
        this._tasks = this._state.tasks;
        this._user = this._state.user;
        this._taskList = groupBy(this._tasks, 'isSamePage' , false);
        this._pagetask = this._tasks.filter(task => task.isSamePage);
        this._pagetaskExcude = this._tasks.filter(task => !task.isSamePage);
        this._events = {};
        this._activeMarker = null;

        // dropdown selected value
        this._all = this._query._getAll();

        this._statick_key = ['page', 'priority', 'status'];
        this.priority = this._all.query.priority || null;
        this.status = this._all.query.status || null;
        this.page = this._all.query.page || null;


        this._explorer = this._renderExplorer();
        this._renderMaker();
    }

    set(value){
        this._query._setMkr(value, push = true);
    }
    remove(){
        this._query._removeMkr(push = true);
    }
    get(){
        return this._mkr;
    }

    

    on(event, callback) {
        if (!this._events[event]) {
            this._events[event] = [];
        }
        this._events[event].push(callback);
    }
    
    _emit(event, data) {
        if (this._events[event]) {
            this._events[event].forEach(cb => cb(data));
        }
    }

    
    _handleTaskRedirectClick( task ){
        const confirmRedirect = window.confirm(
            `This task is from another page:\n\n${task.href}\n\nDo you want to navigate there?`
        );

        const taskQuery = new QueryHelper(task.href);
        this._statick_key.forEach(key => {
            if(this[key]) {
                taskQuery._add(key, this[key] );
            }else{
                taskQuery._remove(key);
            }
        });

        taskQuery._add('mkr', task.id);
        task.href = taskQuery._toString();
        console.log('task.href',task.href)


        if (confirmRedirect) {
            window.location.href = task.href;
        }
    }

    _toggleMarkerActive(clickedId) {

        if(this._user.role === 'guest'){ console.error('Guest user cannot create marker'); return; }

        const clickedIdStr = String(clickedId);
        const activeId = this._activeMarker?.getAttribute('mkr-id') || null;
    
        if (activeId === clickedIdStr) {
            this._previousActiveId = activeId;
            this._deactivateMarker(clickedId);
            return;
        }
    
        if (activeId) {
            this._previousActiveId = activeId;
            this._deactivateMarker(activeId);
            const positionMaker = this._dom.get(`[mkr-id="${activeId}"]`)[0];
            

        }
    
        this._previousActiveId = activeId;
        this._activateMarker(clickedId);
    }
    _activateMarker(id) {
        const elements = document.querySelectorAll(`[mkr-id="${id}"]`);
        if (!elements.length) return;
    
        elements.forEach(el => el.classList.add('active'));
        this._activeMarker = elements[0]; // Save any one element as reference
    
        const taskId = parseInt(id);
        const previousId = this._previousActiveId ? parseInt(this._previousActiveId) : null;

        const positionCard = this._dom.get(`.explorer-task[mkr-id="${id}"]`)[0];
        if(positionCard){
            positionCard.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }

        console.log('Marker Activated', {taskId , previousId});
        this._emit('click', { taskId, previousId, active: true, element: elements[0] });
    }
    
    _deactivateMarker(id) {
        const elements = document.querySelectorAll(`[mkr-id="${id}"]`);
        if (!elements.length) return;
    
        elements.forEach(el => el.classList.remove('active'));
    
        const taskId = parseInt(id);
        const previousId = this._previousActiveId ? parseInt(this._previousActiveId) : null;

        console.log('Marker Deactivated', {taskId , previousId});
        this._emit('click', { taskId, previousId, active: false, element: elements[0] });
    
        if (this._activeMarker?.getAttribute('mkr-id') === String(id)) {
            this._activeMarker = null;
        }
    }


    _createMarker(index, task) {
        const marker = this._dom.create({
            id: "marker",
            className: "mkr mkrClick f_ marker-floating",
            inner: this.indexCount,
            attributes: { 
                'mkr-id': task.id,
                'priority': task.priority,
                'status': task.status
            }
        });
        this._dom.style(marker, { 
            position:'absolute',
            top:task.y,
            left:task.x,
            transform:`translate(${task.screeninfo.document.x}px, ${task.screeninfo.document.y}px)`
        });
        marker.addEventListener('click', (e) => {
            this._toggleMarkerActive(task.id);
        });
        this._dom.append(document.body, marker);


        let { isSameUser } = this._state.getUserPermissions(task);


        if(isSameUser){
        // Check if this element already has a dragable instance
        if (!this._dragInstances) this._dragInstances = {};
                
        // Remove previous dragable instance if it exists
        if (this._dragInstances[task.id]) {
            this._dragInstances[task.id].destroy();
        }
        
        // Create new dragable instance and store it
        this._dragInstances[task.id] = new Dragable({
            body: `.mkr[mkr-id="${task.id}"]`,
            trigger: `.mkr[mkr-id="${task.id}"]`,
            storageKey: null,
            type: 'free',
            initialPosition: {
                x: task.screeninfo.document.x,
                y: task.screeninfo.document.y
            }
        });
        
        this._dragInstances[task.id].on('dragEnd', async (data) => {
            console.log('Drag Move', data.position);
            const payload = {
                "id": task.id,
                "x": data.position.x,
                "y": data.position.y
            }
            const res = await this._api.updateTaskPosition(payload);
            console.log(res);
        });
        }


        return marker;
    }

    _createMarkerCard(task){
        const formattedDate = new Date(task.due_date).toLocaleDateString('en-US', {
            month: 'long', day: 'numeric', hour: 'numeric', minute: 'numeric'
        });

        const markerCard = this._dom.create({
            tag: "div",
            className: "explorer-task mkrClick f_padding_sm  task-card f_bg_accent f_radius f_transition f_border_accent",
            attributes: {
                "mkr-id": task.id
            }
        });

        const CardHtml = ` <div class="task-meta f_row"><div class="task-time f_text_primary">${formattedDate}</div><div class="task-tags"><div class="f_text_badge_text f_text_accent">${task.page || 'index'}</div><div class="f_text_badge_text f_text_accent ${task.status}">${task.status}</div><div class="f_text_badge_text f_text_accent ${task.priority}">${task.priority}</div></div></div><div class="task-title f_text_primary">${task.title}</div><div class="task-desc f_text_primary">${task.description}</div>`;

        markerCard.appendChild(this._dom.Fragment(CardHtml));
        markerCard.addEventListener('click', (e) => {
            if(task.isSamePage){
                this._toggleMarkerActive(task.id);
            }else{
                this._handleTaskRedirectClick(task);
            }
        });
        this._dom.append(this._explorer[0], markerCard);
        return markerCard;
    }

    _MarkerAdded(task){
        console.log('task--->',task)
        this._createMarkerCard(task);
        this._createMarker(this._pagetask.length, task);
    }

    _MarkerRefresh(taskId){
        this._tasks = this._state.tasks;

        const task = this._tasks.find(task => task.id === taskId);
        


        // .explorer-task[mkr-id="${taskId}"] clone and replace and after remove the old one and append new
        const oldCard = this._dom.get(`.explorer-task[mkr-id="${taskId}"]`)[0];
        const newCard = this._createMarkerCard(task);
        oldCard.parentNode.replaceChild(newCard, oldCard);

    }

    _createExplorer(){
        const explorerHtml = ` <div class="f-gd f-px--n f-py--m"><div class="f_bg_gradient f_space"><div class="f_title f_text_primary f_text_accent f_text_white explorer-header">Bug Explorer</div></div></div><div class="filter-by f_margin_sm f_row f_full_width f_space_x"><div class="priority f_col f_input arrow_down small_arrow f_half_width f_border f_radius"></div><div class="status f_col f_input arrow_down small_arrow f_half_width f_border f_radius"></div><div class="page-wise f_col f_input arrow_down small_arrow f_full_width f_border f_radius"></div></div><div class="taskList f_space_x"></div>`;
        const explorer = this._dom.create({
            id: "explorer",
            className: "f_box_shadow f_bg_accent f_border_accent bug-explorer",
            inner: explorerHtml
        });
        return explorer;
    }

    _renderMaker( initial = true ){
        // remove all the the mkr-id
        this._tasks = this._state.tasks;
        this._taskList = groupBy(this._tasks, 'isSamePage' , false);
        this._pagetask = this._tasks.filter(task => task.isSamePage);
        this._pagetaskExcude = this._tasks.filter(task => !task.isSamePage);


        if(initial){
            this._dom.get('[mkr-id]').forEach(el => el.remove());
        }else{
            this._dom.get('.explorer-task').forEach(el => el.remove());
        }

        Object.keys(this._taskList).forEach(key => {
            this.indexCount = 1;
            this._taskList[key].forEach((task, index) => {

                const isMatch =
                        (!this.priority || task.priority === this.priority) &&
                        (!this.status || task.status === this.status) &&
                        (!this.page || task.page === this.page);
                if(key === 'true'){
                    if(isMatch && initial){
                        this._createMarker(this.indexCount, task);
                        this.indexCount++;
                    }
                }
                if(isMatch){
                    this._createMarkerCard(task);
                }
            });

            
        });

        

        
    }

    _renderExplorer(){
        const explorer = this._createExplorer();
        this._dom.append(document.body, explorer);
        const explorerList = this._dom.get('.taskList', explorer);

        this._setupDropdown(explorer, '.priority', this._state.priority, 'Priority', 'priority', this.priority);
        this._setupDropdown(explorer, '.status', this._state.status, 'Status', 'status', this.status);

        const pageList = groupBy(this._tasks, 'page').keys;
        this._setupDropdown(explorer, '.page-wise', pageList, 'Page', 'page', this.page);

        new Dragable({
            body: "#explorer",
            trigger: ".f-py--m",
            type: 'snap',
            initialPosition: { x: 10, y: 70 },
            offset: { top: 10, bottom: 10, left: 70, right: 70 }
        });


        return explorerList;
    }

    _toggleExplorer(){
        const explorer = document.querySelector("#explorer");
        if (explorer) {
            explorer.remove();
        } else {

            this._explorer = this._renderExplorer();
            this._renderMaker(false);

            
        }
    }

    _setupDropdown(container, selector, data, placeholder, filterKey) {
        const dropdown = new DropdownSelect({
            element: container.querySelector(selector),
            data,
            type: "single",
            style: "picker",
            placeholder,
            isClearable: true,
            prefetch: filterKey,
        });
        dropdown._element.addEventListener('change', (e) => {
            this[filterKey] = e.detail[0] || null;
            this._renderMaker( true );
            this._activeMarker = null;
            this._previousActiveId = null;
            this._emit('change', e.detail);
        });
    }

    


}
