import {
    slug
} from "./env.js";
import DOM from "./utils/dom.js";
import QueryHelper from "./utils/query-helper.js";
import Storage from "./utils/storage.js";
import { groupBy } from "./utils/utils.js";



export default class api {
    constructor(state, store) {
        this.state = state;
        this._store = store;

        this.endpoint = this.state.endpoint;
        this.devMode = this.state.devMode;
        this._query = new QueryHelper();

        console.group("API Operations");
        this.initialized = this.initialize();

    }

    async initialize() {

        // const user = await this.loginUser();
        const projectId = await this.getProject();

        const user = new Storage().getUser();
        if(user){
            if(user.id === 7){
                user.role = "guest";
            }

            this.state.setState("user", user, 'store');
            this._printUser(user);
        }

        if (!user) {
            console.error("No user found");
            return { message: "No user found", login: false , hasProject: projectId };
        }

        

        if (!projectId) {
            console.error("No project found");
            return { message: "No project found",  login: true, hasProject: projectId };
        }
        const tasks = await this.getTasks(projectId);

        return {
            message: "User logged in",
            login: true,
            hasProject: true,
            isTasks: tasks
        };

        
    }


    headers(type, payload = null) {
        const get = {
            method: "GET",
            headers: {
                "Content-Type": "application/json"
            }
        };
        const post = {
            method: "POST",
            headers: {
                "Content-Type": "application/json"
            },
            body: payload ? JSON.stringify(payload) : null
        };
        const patch = {
            method: "PATCH",
            headers: {
                "Content-Type": "application/json"
            },
            body: payload ? JSON.stringify(payload) : null
        };

        if (type === "GET") {
            return get;
        } else if (type === "POST") {
            return post;
        } else if (type === "PATCH") {
            return patch;
        }
    }


    async getProject() {

        if (this._store.getProject()) {
            this.state.setState("project", this._store.getProject(), 'store');
            this.state.setState("assignees", this._store.getAssignees(), 'store');
            return this._store.getProject().project_id;
        }

        const hostname = window.location.hostname;
        // const hostname = '192.168.0.111';

        const res = await fetch(this.endpoint + `${slug.get_project}=${hostname}`, this.headers("GET"))
            .then((res) => res.json())
            .then((data) => {
                if (data.properties.projects) {
                    this.state.setState("project", data.properties.projects, 'api');
                    this.state.setState("assignees", data.properties.member, 'api');

                    this._store.storeProject(data.properties.projects);
                    this._store.storeAssignees(data.properties.member);
                }
                if (data?.properties && Object.keys(data.properties).length > 0) {
                    return data.properties.projects.project_id;
                } else {
                    return false;
                }
            });
        return res;
    }

    _printUser(user){
        this.state.devMode = true
        if(this.state.devMode){
        const dom = new DOM();
        const userWrapper = dom.create({
            id: "user",
            inner: ` <div class="f-shadow f-w--h"><div class="f-gd f-px--n f-py--m">User Info </div><div class="f-px--n f-py--m f-f"><div class="f-f--j f-w--f f-py--s"><div class="f-w--b">ID</div><div class="f-w--n">${user.id}</div></div><div class="f-f--j f-w--f f-py--s"><div class="f-w--b">User</div><div class="f-w--n">${user.role}</div></div><div class="f-f--j f-w--f f-py--s"><div class="f-w--b">Email</div><div class="f-w--n">${user.email}</div></div><div class="f-f--j f-w--f f-py--s"><div class="f-w--b">Name</div><div class="f-w--n">${user.name}</div></div></div></div>`
        });
        dom.style(userWrapper,{
            "position": "fixed",
            "bottom": "10px",
            "left": "10px",
            "z-index": "1",
        });
        dom.append(document.body, userWrapper);
        }
    }

    async loginUser(email = "isha@2cube.studio", password = "isha@123456") {

        if (this._store.getUser()) {
            this.state.setState("user", this._store.getUser(), 'store');
            this._printUser(this._store.getUser());
            return true;
        }
        

        this._store.deleteAllTasks();
        const res = await fetch(this.endpoint + `${slug.login_user}`, this.headers("POST", {
                email,
                password
            }))
            .then((res) => res.json())
            .then((data) => {
                if (data?.id) {
                    this.state.setState("user", data, 'api');
                    this._store.storeUser(data);
                    this._printUser(data);
                    return {
                        message: "User logged in",
                        login: true
                    };
                } else {
                    return {
                        message: data.message,
                        login: false
                    }
                }
            }).catch((err) => {
                console.error(err);
                return false;
            });
        return res;
    }

    async getTasks(payload) {

        // if (this._store.getTasks()) {
        //     this.state.setState("tasks", this._store.getTasks(), 'store');
        //     return true;
        // }

        const res = await fetch(this.endpoint + `${slug.get_tasks}?project_id=${payload}`, this.headers("GET"))
            .then((res) => res.json())
            .then((data) => {
                if (!data?.error) {

                    const prepareData = data.properties.map(task => {
                        const taskPageName = this._query._getPageName(task.href);
                        const currentPageName = this._query._getPageName(window.location.href);
                        
                        // Consider both as "Index" if they don't have specific page names
                        task.page = taskPageName;
                        
                        // Special case: both are index pages (no specific page name)
                        if ((taskPageName === 'index' && currentPageName === 'index') || 
                            (taskPageName === currentPageName)) {
                            task.isSamePage = true;
                        } else {
                            task.isSamePage = false;
                        }
                        
                        return task;
                    });


                    this.state.setState("tasks", prepareData, 'api');
                    this._store.storeTasks(prepareData);
                    return true;
                } else {
                    console.error('No tasks found');
                    return false;
                }
            });

        return res;
    }

    async createTask(payload) {
        console.log(payload);
        const res = await fetch(this.endpoint + `${slug.create_task}`, this.headers("POST", payload))
            .then(async (res) => {
                const data = await res.json();
                if (res.status !== 201) {
                    console.error(data.error);
                    return {
                        message: data.error,
                        success: false
                    };
                } else {
                    data.isSamePage = payload.isSamePage;
                    data.page = payload.page;

                    this._store.pushTask(data);
                    const totalTasks = this.state.addTask(data);
                    console.log(`Task created: ${data.id}`,totalTasks);
                    return {
                        message: "Task created",
                        success: true,
                        data:data
                    };
                }

            }).catch((err) => {
                console.error(err);
                return false;
            });
        return res;
    }

    async updateTask(payload) {
        const res = await fetch(this.endpoint + `${slug.update_task}`, this.headers("PATCH", payload))
            .then(async (res) => {
                const data = await res.json();
                if (res.status !== 200) {
                    console.error(data.message);
                    return false;
                } else {
                    return data;
                }
            })
            .then((data) => {
                if (data) {
                    data.properties.isSamePage = payload.isSamePage;
                    data.properties.page = payload.page;
                    
                    this._store.updateTask(data.properties);
                    this.state.updateTask(data.properties);
                    console.log(`Task updated: ${data.properties.id}`);
                    console.table(payload);
                }
                return data;
            }).catch((err) => {
                console.error(err);
                return false;
            });
        return res;
    }

    async updateTaskPosition(payload) {
        /*
            slug is  -> slug.update_task_position
            accept body json -> { "id": 4, "x": 970, "y": 266 }
            method -> PATCH
        */
        const res = await fetch(this.endpoint + `${slug.update_task_position}`, this.headers("PATCH", payload))
            .then(async (res) => {
                const data = await res.json();
                if (res.status !== 200) {
                    console.error(data.message);
                    return false;
                } else {
                    return data;
                }
            })
            .then((data) => {
                if (data) {
                    this._store.updateTask(data.properties);
                    this.state.updateTask(data.properties);
                    console.log(`Task updated: ${data.properties.id}`);
                    console.table(payload);
                }
                return data;
            }).catch((err) => {
                console.error(err);
                return false;
            });
        return res;
    }

    



}

