export default class DOM {

    constructor() {
        

        this._keysArr = ["title", "description", "due_date", "assigned_to", "priority", "status", "submit", "cancel"];
    }
    

    Fragment(el) {
        return document.createRange().createContextualFragment(el)
    }

    // create() call that time error. and want to fixed

    create( {
        tag = 'div',
        id = '',
        className = '',
        inner = '',
        isDraggable = false,
        attributes = {},
    }) {

        
        const element = document.createElement(tag);
        if (id) {
            element.id = id;
        }
        if (className) {
            element.className = className;
        }

        if (inner && tag !== 'input') {
            // element.innerHTML = inner;
            if (typeof inner === 'string' || typeof inner === 'number' ) {
                element.innerHTML = inner;
              } else if (inner instanceof Node) {
                element.innerHTML = ''; // optional: clear existing content
                element.appendChild(inner);
              }
        }
        if (inner && tag === 'input') {
            element.value = inner;
        }

        if (isDraggable) {
            element.setAttribute('data-no-drag', 'true');
        } 

        // add attributes
        for (const [key, value] of Object.entries(attributes)) {
            element.setAttribute(key, value);
            if(key === 'contenteditable' && !value){
                element.setAttribute('disabled', 'true');
            }

            this._keysArr.forEach((el) => {
                if( value === el ){
                    element.setAttribute('tabindex',0);
                }
            });
            
            
            
        }

        

        return element;
    }

    createTree(config) {
        const {
            tag = 'div',
            id = '',
            className = '',
            inner = '',
            isDraggable = false,
            attributes = {},
            children = []
        } = config;
    
        const element = this.create({ tag, id, className, inner, isDraggable, attributes });

    
        for (const childConfig of children) {
            const childElement = this.createTree(childConfig);
            element.appendChild(childElement);
        }
    
        return element;
    }



    style(element, style) {
        for (const [key, value] of Object.entries(style)) {
            element.style[key] = value;
        }
    }

    // add class
    addClass(element, className , isForce = false) {
        if(!isForce){
            const _className = className.split(' ');
            _className.forEach((el) => {
                element.classList.add(el);
            });
            // element.classList.add(className);
        }else{
            const elements = document.querySelectorAll(element);
            elements.forEach(el => el.classList.add(className));
        }
    }

    // remove class
    removeClass(element, className) {
        
        if(element.classList.contains(className)){
            element.classList.remove(className);
        }
    }

    // get querySelectorAll
    get(selector , context = document) {
        if (context) {
            return context.querySelectorAll(selector);
        }else{
            return document.querySelectorAll(selector);
        }
    }

    _normalizeValue(value) {
        if (value === null || value === undefined || value === 'null' || value === 'undefined') return null;
        if (isNaN(value) && typeof value !== 'string') return null;
        return String(value);
    };

    // getFormValue
    _getFormValue(form) {
        const formData = {};
        const fields = form.querySelectorAll('[name]');
        fields.forEach((el) => {
            const data = this._normalizeValue(el.value || el.getAttribute('value') || null);
            formData[el.getAttribute('name')] = data;
        });
        return formData;
    }
    

    // get querySelector
    getOne(selector, context = document) {
        if (context) {
            return context.querySelector(selector);
        }else
        {
            return document.querySelector(selector);
        }
        
    }

    // set attribute
    setAttr(element, attribute, value) {
        element.setAttribute(attribute, value);
    }

    // get attribute
    getAttr(element, attribute) {
        return element.getAttribute(attribute);
    }

    /* appendChild */
    append(parent, child) {
        if(Array.isArray(child)){
            child.forEach(el => {
                parent.appendChild(el);
            });
        }else{
            parent.appendChild(child);
        }
        return parent;
    }
    /* removeChild */
    remove(parent, child) {
        parent.removeChild(child);
    }


    /* add event listener */
    on(element, event, callback) {
        element.addEventListener(event, callback);
    }

    /* remove event listener */
    off(element, event, callback) {
        element.removeEventListener(event, callback);
    }
}