
import Mkr from "./mkr.js";
import QueryHelper from "./query-helper.js";
import { getDocumentInfo, getSystemInfo } from "./utils.js";

export default class Hooks {
    constructor(api) {
        this.api = api;
        this.state = this.api.state;
        this._query = new QueryHelper();
    }

    


    formCreate( form ) {
        form.on("formCreate", (data) => {
            const { element } = data;
            const x = this.state.mousePos.x;
            const y = this.state.mousePos.y;
            const formWidth = element.offsetWidth;
            const formHeight = element.offsetHeight;
            const windowWidth = window.innerWidth;
            const windowHeight = window.innerHeight;
        
            let adjustedLeft, adjustedTop;
        
            // --- Horizontal position (left/right) ---
            if (x + formWidth + 10 <= windowWidth) {
                adjustedLeft = x; // Right of cursor
            } else {
                adjustedLeft = x - formWidth; // Left of cursor
                if (adjustedLeft < 10) adjustedLeft = 10;
            }
        
            // --- Vertical position (top/bottom) ---
            if (y + formHeight + 10 <= windowHeight) {
                adjustedTop = y; // Below cursor
            } else {
                adjustedTop = y - formHeight; // Above cursor
                if (adjustedTop < 10) adjustedTop = 10;
            }
        
            // Apply position
            element.style.position = "absolute";
            element.style.left = adjustedLeft + "px";
            element.style.top = adjustedTop + "px";
        
            setTimeout(() => {
                element.classList.add("fi");
            }, 100);
        });
        
        
    }

    formSubmit( form ) {
        const screeninfo = getSystemInfo();
        let documentinfo = getDocumentInfo();
        


        form.on("formSubmit", async (data) => {
            console.log("Form submitted:", data);
            documentinfo = {
                ...documentinfo,
                "x": this.state.mousePos.x,
                "y": this.state.mousePos.y
            };
            const json = {
                "project_id": this.state.project.project_id,
                "created_by": this.state.user.id,
                "assigned_to": [parseInt(data.assigned_to)],
                "title": data.title,
                "mode": "comment",
                "href": this._query._senitizeUrl(),
                "description": data.description,
                "status": data.status,
                "priority": data.priority,
                "due_date": data.due_date,
                "screeninfo": {
                    ...screeninfo,
                    "document": {
                       ...documentinfo
                    }
                },
                "isSamePage": true,
                "page": this._query._getPageName(window.location.href)
            }




            const res = await this.api.createTask(json);
            console.log(res)
            if(res.success){
                form.removeForm();
                this.state.setStage('init',`formSubmit Hook>success`);
                console.log(json);
                console.log("this.state.marker",this.state.marker);
                if(this.state.marker){
                    this.state.marker._MarkerAdded(res.data);
                }else{
                    this.state.marker = new Mkr(this.state);
                    this.state.marker._MarkerAdded(res.data);
                } 
                    
                return res;
            }else{
                return false;
            }
            
        });
    }


    formUpdate(form,functionToCall) {
        form.on("formUpdate", async (data) => { 
            const json = {
                "id": data.id,
                "assigned_to": [parseInt(data.assigned_to)],
                "title": data.title,
                "description": data.description,
                "status": data.status,
                "priority": data.priority,
                "due_date": data.due_date,
                "isSamePage": true,
                "page": this._query._getPageName(window.location.href)
            }
            const res = await this.api.updateTask(json);
            if(res){
                form.removeForm();
                this.state.setStage('init', `formUpdate Hook>success`);
                functionToCall();
                this.state.marker._MarkerRefresh(data.id);
                return res;
            }else{
                return false;
            }
        });
    }

    

    formWatch(form) {
        form.on("formWatch", (data) => {
            const submitBtn = form.querySelector('#f--submit');
            console.log("Form changed:", data.changedField);
            console.log("Current data:", data.formData);
            console.log("Is valid:", data.isValid);
            if (!data.isValid) {
                submitBtn.classList.add('disabled');
            } else {
                submitBtn.classList.remove('disabled');
            }
        });
    }


}
