export default class QueryHelper {
    constructor(url = window.location.href) {
      this._url = new URL(url);
    }

    _senitizeUrl(url = window.location.href) {
      // remove mkr , page , priority , status and return senitizedUrl
      const keys = ['mkr', 'page', 'priority', 'status'];
      keys.forEach(key => {
        this._remove(key);
      });
      return this._toString();
    }

    _getPageName(url = window.location.href) {
      const parsedUrl = new URL(url);
      const pathname = parsedUrl.pathname;
      const pageName = pathname.split('/').pop().split('.')[0];
      return pageName || 'index';
    }
    
    _getAll(url = window.location.href) {
      const parsedUrl = new URL(url);
      const query = {};
      parsedUrl.searchParams.forEach((value, key) => {
        query[key] = value;
      });

      return {
        hostname: parsedUrl.hostname,
        pathname: parsedUrl.pathname,
        search: parsedUrl.search,
        hash: parsedUrl.hash,
        query
      };
    }
  
    _add(key, value, push = false) {
      
      if(push){
        this._url = new URL(window.location.href);
      }
      this._url.searchParams.set(key, value);
      if (push) {
        window.history.pushState({}, '', this._toString() , true);
      }
      
      return this;
    }

    // _add(key, value, push = false) {
    //   this._url.searchParams.set(key, value);
    //   if (push) {
    //     window.history.pushState({}, '', this._toString());
    //   }
    //   return this;
    // }
   
  
    _remove(key, push = false) {
      if(push){
        this._url = new URL(window.location.href);
      }
      this._url.searchParams.delete(key);
      if (push) {
        window.history.pushState({}, '', this._toString() , true);
      }
      return this;
    }
  
    _has(key) {
      return this._url.searchParams.has(key);
    }
  
    _get(key) {
      return this._url.searchParams.get(key);
    }
  
    _toString() {
      return this._url.toString();
    }
  
    // Common keys with push option
    get _mkr() { return this._get('mkr'); }
    set _mkr(value) { this._add('mkr', value , true); }
    
    // _setMkr(value, push = false) {
    //   return this._add('mkr', value, push);
    // }
  
    get _page() { return this._get('page'); }
    set _page(value) { this._add('page', value); }
    
    // _setPage(value, push = false) {
    //   return this._add('page', value, push);
    // }
  
    get _priority() { return this._get('priority'); }
    set _priority(value) { this._add('priority', value); }
    
    // _setPriority(value, push = false) {
    //   return this._add('priority', value, push);
    // }
  
    get _status() { return this._get('status'); }
    set _status(value) { this._add('status', value); }
    
    // _setStatus(value, push = false) {
    //   return this._add('status', value, push);
    // }
  
    _removeMkr(push = true) { return this._remove('mkr', push); }
    _removePage(push = true) { return this._remove('page', push); }
    _removePriority(push = true) { return this._remove('priority', push); }
    _removeStatus(push = true) { return this._remove('status', push); }
}
