import DOM from "./dom.js";

export default class FormValidation {
    constructor() {
        this.customRules = {
            title: { required: true, minLength: 3, maxLength: 50, },
            description: { required: true, minLength: 10, maxLength: 500, },
            due_date: { required: true, },
            assigned_to: { required: true, },
            priority: { required: true, },
            status: { required: true, },
        }
        this._dom = new DOM();
    }

   

    validate(form, newData, originalData) {
        const fields = Object.keys(newData).filter(key => key !== 'id');
        const submitBtn = form.querySelector('#f--submit');
        let hasChanges = false;
        let isValid = true; // Start with true and set to false if validation fails
        
        const extractedData = {};
        fields.forEach((key) => {
            // Handle special case for assigned_to which might be an array
            let oldValue = key === "assigned_to" && Array.isArray(originalData[key]) 
                ? originalData[key][0] 
                : originalData[key];
                
            let newValue = key === "assigned_to" && !isNaN(newData[key]) 
                ? parseInt(newData[key]) 
                : newData[key];
            
            // Normalize values for comparison
            oldValue = this._dom._normalizeValue(oldValue);
            newValue = this._dom._normalizeValue(newValue);
            
            // Check if values are different
            if (oldValue !== newValue) {
                hasChanges = true;
            }
            
            // Get the field element
            const field = form.querySelector(`[name="${key}"]`);
            
            // Check validation rules for the new value
            const rules = this.customRules[key];
            if (rules) {
                let fieldValid = true;
                
                if (rules.required && (newValue === null || newValue === '')) {
                    fieldValid = false;
                }
                
                if (rules.minLength && newValue && newValue.length < rules.minLength) {
                    fieldValid = false;
                }
                
                if (rules.maxLength && newValue && newValue.length > rules.maxLength) {
                    fieldValid = false;
                }
                
                if (field && !fieldValid) {
                    field.classList.add('invalid');
                    isValid = false;
                } else if (field) {
                    field.classList.remove('invalid');
                }
            }
            
            extractedData[key] = { old: oldValue, new: newValue };
        });

        this.observeFormFields(form, extractedData);
        const result = hasChanges && isValid;
        if (submitBtn) {
            submitBtn.classList.toggle('disabled', !result);
        }
        return result;
    }

    observeFormFields(form, extractedData) {
        const rules = this.customRules;
        const submitBtn = form.querySelector('#f--submit');
        let formHasChanges = false;
        let formIsValid = true;
        
        Object.keys(extractedData).forEach((key) => {
            // Skip the id field as it's not a form element
            if (key === "id") return;
            
            const field = form.querySelector(`[name="${key}"]`);
            if (!field) {
                console.warn(`Field"${key}"not found`);
                return;
            }

            const type = field.getAttribute('type');
            const event = type === "hidden" ? "change" : "input";

            field.addEventListener(event, (e) => {
                const currentValue = this.getFieldValue(field);
                let isValid = true;
                
                // Check if value matches original
                const valueChanged = currentValue != extractedData[key].old;
                //console.log({valueChanged});
                
                // Apply validation rules if the field has them
                if (rules[key] && valueChanged) {
                    const rule = rules[key];
                    
                    if (rule.required && !currentValue) {
                        isValid = false;
                    }
                    
                    if (rule.minLength && currentValue.length < rule.minLength) {
                        isValid = false;
                    }
                    
                    if (rule.maxLength && currentValue.length > rule.maxLength) {
                        isValid = false;
                    }
                }

                field.classList.toggle('invalid', !isValid);
                
                // Check all fields to determine overall form validity
                let allFieldsValid = true;
                let anyFieldChanged = false;
                
                Object.keys(extractedData).forEach((fieldKey) => {
                    if (fieldKey === "id") return;
                    
                    const fieldEl = form.querySelector(`[name="${fieldKey}"]`);
                    if (!fieldEl) return;
                    
                    const fieldValue = this.getFieldValue(fieldEl);
                    const fieldChanged = fieldValue != extractedData[fieldKey].old;
                    
                    if (fieldChanged) {
                        anyFieldChanged = true;
                        
                        // Check validation rules
                        if (rules[fieldKey]) {
                            const fieldRule = rules[fieldKey];
                            
                            if (fieldRule.required && !fieldValue) {
                                allFieldsValid = false;
                            }
                            
                            if (fieldRule.minLength && fieldValue.length < fieldRule.minLength) {
                                allFieldsValid = false;
                            }
                            
                            if (fieldRule.maxLength && fieldValue.length > fieldRule.maxLength) {
                                allFieldsValid = false;
                            }
                        }
                    }
                });
                
                // Update submit button state
                if (submitBtn) {
                    if (anyFieldChanged && allFieldsValid) {
                        submitBtn.classList.remove('disabled');
                    } else {
                        submitBtn.classList.add('disabled');
                    }
                }
            });
        });
    }

    getFieldValue(field) {
        const type = field.getAttribute('type');
        if (type === 'hidden') {
            return field.getAttribute('value') || '';
        }else{
         return field.value || '';
        }
    }
}
