import api from "./api.js";
import State from "./state.js";
import ControlManager from "./utils/controlManager.js";
import FormManager from "./utils/FormManager.js";
import QueryHelper from "./utils/query-helper.js";
import Storage from "./utils/storage.js";


class FlagBugApp {
    constructor(options) {
        this.endpoint = options.endpoint;
        this.devMode = options.devMode;
        this.apiLocal = options.apiLocal;
        this.explorer = options.explorer || false;

        this.store = new Storage();


        this.state = new State(this.endpoint, this.devMode);
        this.state.setState("explorer", this.explorer, 'app');
        this.api = new api(this.state, this.store);




        this.api.initialized.then(async (res) => {
            console.log("API initialized", res);
            if (res.hasProject) {
                this.formManager = new FormManager(this.state);
                this.controlManager = new ControlManager(this.state, this.api);

                // const formManager = new FormManager(this.state);
                //         const formHook = new Hooks(this.api);
                //         formHook.formCreate(formManager);
                //         formHook.formSubmit(formManager);
                //         formManager.createForm({
                //             viewportInfo: null,
                //             id: "TaskForm",
                //             type: "create",
                //         });

            }
        }).then(() => {
            const mkr = new QueryHelper()._mkr;
            if (mkr) {
                const marker = document.querySelector(`.mkr[mkr-id="${mkr}"]`);
                if (marker) {
                    marker.click();
                }
            }
        });

    }


}



const apiLocal = true;
let endpoint = "http://192.168.0.160:3030/api/v1/";
if (!apiLocal) {
    endpoint = "https://bugvault.2cube.studio/api/v1/";
}
new FlagBugApp({
    devMode: false,
    endpoint: endpoint,
    apiLocal: apiLocal
});

window.FlagBugApp = FlagBugApp;