/*
I need to generate tooltip class where I need those thing

Requirement List

#Core Options
•	content: Text or HTML to display inside the tooltip.
•	placement: Top, Bottom, Left, Right, Auto.
•	trigger: Hover, Click
•	delay: Show/hide delay in ms.
•	animation: Enable/disable animation (fade, slide). - just use class. I'll manage from css side
•	offset: Distance between tooltip and target element.
•	theme: Light, dark themes.
•	maxWidth: Limit tooltip width.

#Positioning Options
•	boundary: Viewport, window, or scroll parent.
•	flip: Auto-flip if not enough space.
•	arrow: Show/hide tooltip arrow.

#Behavior Options
•	interactive: Allow mouse interaction inside tooltip.
•	closeOnClickOutside: Dismiss tooltip on outside click.
•	hideOnScroll: Auto-hide tooltip on page scroll.
•	sticky: Tooltip follows mouse on hover.
•	once: Show tooltip only once per session.

#Customization Options
•	customClass: Add custom CSS classes.
•	html: Accept HTML content.
•	template: Full custom tooltip template.

#Integration Options
•	selector: Target via CSS selector or element.
•	dataAttributes: Use data-tooltip, data-placement, etc.
•	globalConfig: Set default config globally.
*/
export default class Tooltip {
    constructor(options = {}) {
      // Default configuration
      this.defaults = {
        // Core Options
        content: '',
        placement: 'top',
        trigger: 'hover',
        delay: {
          show: 300,
          hide: 200
        },
        animation: 'fade',
        offset: 8,
        theme: 'dark',
        maxWidth: 300,
        
        // Positioning Options
        boundary: 'viewport',
        flip: true,
        arrow: true,
        
        // Behavior Options
        interactive: false,
        closeOnClickOutside: true,
        hideOnScroll: true,
        sticky: false,
        once: false,
        
        // Customization Options
        customClass: '',
        html: false,
        template: '<div class="flagbug-tooltip fade-in-el" role="tooltip"><div class="flagbug-tooltip-arrow"></div><div class="flagbug-tooltip-content"></div></div>',
        
        // Integration Options
        selector: null,
        dataAttributes: true,
        globalConfig: {}
      };
      
      // Merge defaults with provided options
      this.config = { ...this.defaults, ...options };
      
      // State variables
      this._tooltipElement = null;
      this._targetElement = null;
      this._showTimeout = null;
      this._hideTimeout = null;
      this._isVisible = false;
      this._shownOnce = false;
      
      // Initialize
      this._init();
    }
    
    _init() {
      // Apply global config if available
      if (Object.keys(this.config.globalConfig).length > 0) {
        this.config = { ...this.config, ...this.config.globalConfig };
      }
      
      // Initialize tooltips based on selector or data attributes
      if (this.config.selector) {
        this._initializeBySelector();
      } else if (this.config.dataAttributes) {
        this._initializeByDataAttributes();
      }
      
      // Add scroll listener if hideOnScroll is enabled
      if (this.config.hideOnScroll) {
        window.addEventListener('scroll', this._handleScroll.bind(this), { passive: true });
      }
      
    }
    
    _initializeBySelector() {
      const elements = document.querySelectorAll(this.config.selector);
      if (elements.length) {
        elements.forEach(el => {
          this._attachToElement(el);
        });
      }
    }
    
    _initializeByDataAttributes() {
      const elements = document.querySelectorAll('[data-tooltip]');
      if (elements.length) {
        elements.forEach(el => {
          // Extract config from data attributes
          const elementConfig = {
            content: el.getAttribute('data-tooltip'),
            placement: el.getAttribute('data-placement') || this.config.placement,
            trigger: el.getAttribute('data-trigger') || this.config.trigger,
            theme: el.getAttribute('data-theme') || this.config.theme,
            animation: el.getAttribute('data-animation') || this.config.animation
          };
          
          this._attachToElement(el, elementConfig);
        });
      }
    }
    
    _attachToElement(element, elementConfig = {}) {
      // Merge base config with element-specific config
      const config = { ...this.config, ...elementConfig };
      
      // Store config on element
      element._tooltipConfig = config;
      
      // Attach event listeners based on trigger
      if (config.trigger === 'hover') {
        element.addEventListener('mouseenter', this._handleMouseEnter.bind(this, element));
        element.addEventListener('mouseleave', this._handleMouseLeave.bind(this, element));
        
        // For sticky tooltips that follow mouse
        if (config.sticky) {
          element.addEventListener('mousemove', this._handleMouseMove.bind(this, element));
        }
        
      } else if (config.trigger === 'click') {
        element.addEventListener('click', this._handleClick.bind(this, element));
        
        // Close on outside click if enabled
        if (config.closeOnClickOutside) {
          document.addEventListener('click', this._handleOutsideClick.bind(this));
        }
      }
      
      // Make element focusable for accessibility if it isn't already
      if (!element.getAttribute('tabindex')) {
        element.setAttribute('tabindex', '0');
      }
      
      // Add keyboard support
      element.addEventListener('keydown', this._handleKeyDown.bind(this, element));
      
      // Add aria attributes for accessibility
      element.setAttribute('aria-describedby', `tooltip-${this._generateId()}`);
    }
    
    // Event handlers
    _handleMouseEnter(element, event) {
      this._targetElement = element;
      this._scheduleShow(element);
    }
    
    _handleMouseLeave(element, event) {
      // Don't hide if interactive and mouse is moving to tooltip
      if (element._tooltipConfig.interactive && this._tooltipElement) {
        const tooltipRect = this._tooltipElement.getBoundingClientRect();
        if (
          event.clientX >= tooltipRect.left &&
          event.clientX <= tooltipRect.right &&
          event.clientY >= tooltipRect.top &&
          event.clientY <= tooltipRect.bottom
        ) {
          // Mouse is moving to tooltip, don't hide
          return;
        }
      }
      
      this._scheduleHide();
    }
    
    _handleMouseMove(element, event) {
      if (element._tooltipConfig.sticky && this._isVisible) {
        // Update position to follow mouse
        const x = event.clientX;
        const y = event.clientY;
        this._updateStickyPosition(x, y);
      }
    }
    
    _handleClick(element, event) {
      this._targetElement = element;
      
      if (this._isVisible) {
        this._hide();
      } else {
        this._show(element);
      }
    }
    
    _handleOutsideClick(event) {
      if (!this._isVisible || !this._tooltipElement) return;
      
      // Check if click is outside tooltip and target
      const isClickInsideTooltip = this._tooltipElement.contains(event.target);
      const isClickOnTarget = this._targetElement && this._targetElement.contains(event.target);
      
      if (!isClickInsideTooltip && !isClickOnTarget) {
        this._hide();
      }
    }
    
    _handleKeyDown(element, event) {
      // Show on Enter or Space
      if ((event.key === 'Enter' || event.key === ' ') && !this._isVisible) {
        event.preventDefault();
        this._show(element);
      }
      
      // Hide on Escape
      if (event.key === 'Escape' && this._isVisible) {
        event.preventDefault();
        this._hide();
      }
    }
    
    _handleScroll() {
      if (this._isVisible && this.config.hideOnScroll) {
        this._hide();
      }
    }
    
    // Core methods
    _scheduleShow(element) {
      // Clear any existing timeouts
      clearTimeout(this._hideTimeout);
      clearTimeout(this._showTimeout);
      
      // Check if tooltip should only be shown once
      if (element._tooltipConfig.once && this._shownOnce) {
        return;
      }
      
      // Schedule show with delay
      const delay = typeof element._tooltipConfig.delay === 'object' 
        ? element._tooltipConfig.delay.show 
        : element._tooltipConfig.delay;
        
      this._showTimeout = setTimeout(() => {
        this._show(element);
      }, delay);
    }
    
    _scheduleHide() {
      // Clear any existing timeouts
      clearTimeout(this._showTimeout);
      clearTimeout(this._hideTimeout);
      
      // Schedule hide with delay
      const delay = typeof this._targetElement._tooltipConfig.delay === 'object' 
        ? this._targetElement._tooltipConfig.delay.hide 
        : this._targetElement._tooltipConfig.delay;
        
      this._hideTimeout = setTimeout(() => {
        this._hide();
      }, delay);
    }
    
    _show(element) {
      if (this._isVisible) return;
      
      const config = element._tooltipConfig;
      
      // Create tooltip element if it doesn't exist
      if (!this._tooltipElement) {
        this._createTooltipElement(element);
      }
      
      // Set content
      this.setContent(element);
      
      // Position tooltip
      this._position(element);
      
      // Show tooltip
      this._tooltipElement.classList.add('flagbug-tooltip-visible');
      this._tooltipElement.classList.add('fade-in'); // Add fade-in class for animation
      
      // Mark as visible
      this._isVisible = true;
      this._shownOnce = true;
      
      // Add interactive handlers if needed
      if (config.interactive) {
        this._tooltipElement.addEventListener('mouseenter', () => {
          clearTimeout(this._hideTimeout);
        });
        
        this._tooltipElement.addEventListener('mouseleave', () => {
          this._scheduleHide();
        });
      }
      
      
    }
    
    _hide() {
      if (!this._isVisible || !this._tooltipElement) return;
      
      // Hide tooltip
      this._tooltipElement.classList.remove('flagbug-tooltip-visible');
      this._tooltipElement.classList.remove('fade-in'); // Remove fade-in class
      
      // Mark as hidden
      this._isVisible = false;
      
      // Remove tooltip element after animation completes
      setTimeout(() => {
        if (this._tooltipElement && this._tooltipElement.parentNode) {
          this._tooltipElement.parentNode.removeChild(this._tooltipElement);
          this._tooltipElement = null;
        }
      }, 300); // Match CSS transition duration
      
    }
    
    _createTooltipElement(element) {
      const config = element._tooltipConfig;
      
      // Create from template
      const tempDiv = document.createElement('div');
      tempDiv.innerHTML = config.template.trim();
      this._tooltipElement = tempDiv.firstChild;
      
      // Set ID for accessibility
      const tooltipId = `tooltip-${this._generateId()}`;
      this._tooltipElement.id = tooltipId;
      
      // Add theme class
      this._tooltipElement.classList.add(`flagbug-tooltip-theme-${config.theme}`);
      
      // Add custom class if provided
      if (config.customClass) {
        this._tooltipElement.classList.add(config.customClass);
      }
      
      // Set max width
      if (config.maxWidth) {
        this._tooltipElement.style.maxWidth = `${config.maxWidth}px`;
      }
      
      // Hide arrow if disabled
      if (!config.arrow) {
        const arrow = this._tooltipElement.querySelector('.flagbug-tooltip-arrow');
        if (arrow) {
          arrow.style.display = 'none';
        }
      }
      
      // Append to body
      document.body.appendChild(this._tooltipElement);
    }
    
    setContent(element) {
      const config = element._tooltipConfig;
      const contentContainer = this._tooltipElement.querySelector('.flagbug-tooltip-content');
      
      if (!contentContainer) return;
      
      // Set content based on html option
      if (config.html) {
        contentContainer.innerHTML = config.content;
      } else {
        contentContainer.textContent = config.content;
      }
    }
    
    _position(element) {
      const config = element._tooltipConfig;
      const targetRect = element.getBoundingClientRect();
      const tooltipRect = this._tooltipElement.getBoundingClientRect();
      
      // Calculate initial position based on placement
      let top, left;
      let actualPlacement = config.placement;
      
      switch (config.placement) {
        case 'top':
          top = targetRect.top - tooltipRect.height - config.offset;
          left = targetRect.left + (targetRect.width / 2) - (tooltipRect.width / 2);
          break;
        case 'bottom':
          top = targetRect.bottom + config.offset;
          left = targetRect.left + (targetRect.width / 2) - (tooltipRect.width / 2);
          break;
        case 'left':
          top = targetRect.top + (targetRect.height / 2) - (tooltipRect.height / 2);
          left = targetRect.left - tooltipRect.width - config.offset;
          break;
        case 'right':
          top = targetRect.top + (targetRect.height / 2) - (tooltipRect.height / 2);
          left = targetRect.right + config.offset;
          break;
        case 'auto':
          // Determine best placement based on available space
          const placements = ['top', 'right', 'bottom', 'left'];
          const viewportHeight = window.innerHeight;
          const viewportWidth = window.innerWidth;
          
          // Calculate available space in each direction
          const spaces = {
            top: targetRect.top,
            right: viewportWidth - targetRect.right,
            bottom: viewportHeight - targetRect.bottom,
            left: targetRect.left
          };
          
          // Sort placements by available space
          const bestPlacement = placements.sort((a, b) => spaces[b] - spaces[a])[0];
          
          // Recursively position with best placement
          actualPlacement = bestPlacement;
          config.placement = bestPlacement;
          return this._position(element);
      }
      
      // Apply flip if enabled and tooltip would be outside viewport
      if (config.flip) {
        const viewportHeight = window.innerHeight;
        const viewportWidth = window.innerWidth;
        
        // Check if tooltip would be outside viewport
        if (top < 0) {
          // Flip from top to bottom
          top = targetRect.bottom + config.offset;
          actualPlacement = 'bottom';
        } else if (top + tooltipRect.height > viewportHeight) {
          // Flip from bottom to top
          top = targetRect.top - tooltipRect.height - config.offset;
          actualPlacement = 'top';
        }
        
        if (left < 0) {
          // Flip from left to right
          left = targetRect.right + config.offset;
          actualPlacement = 'right';
        } else if (left + tooltipRect.width > viewportWidth) {
          // Flip from right to left
          left = targetRect.left - tooltipRect.width - config.offset;
          actualPlacement = 'left';
        }
      }
      
      // Apply boundary constraints
      if (config.boundary === 'viewport') {
        const viewportHeight = window.innerHeight;
        const viewportWidth = window.innerWidth;
        
        // Constrain to viewport
        top = Math.max(0, Math.min(top, viewportHeight - tooltipRect.height));
        left = Math.max(0, Math.min(left, viewportWidth - tooltipRect.width));
        
        // Update placement based on final position
        if (top <= 0) {
          actualPlacement = 'bottom';
        } else if (top + tooltipRect.height >= viewportHeight) {
          actualPlacement = 'top';
        }
        
        if (left <= 0) {
          actualPlacement = 'right';
        } else if (left + tooltipRect.width >= viewportWidth) {
          actualPlacement = 'left';
        }
      }
      
      // Set position
      this._tooltipElement.style.top = `${top + window.scrollY}px`;
      this._tooltipElement.style.left = `${left + window.scrollX}px`;
      
      // Set placement attribute for CSS styling
      this._tooltipElement.setAttribute('data-placement', actualPlacement);
    }
    
    _updateStickyPosition(x, y) {
      if (!this._tooltipElement) return;
      
      const config = this._targetElement._tooltipConfig;
      const tooltipRect = this._tooltipElement.getBoundingClientRect();
      
      // Position tooltip relative to cursor
      let top = y + config.offset;
      let left = x + config.offset;
      
      // Apply boundary constraints
      if (config.boundary === 'viewport') {
        const viewportHeight = window.innerHeight;
        const viewportWidth = window.innerWidth;
        
        // Constrain to viewport
        top = Math.max(0, Math.min(top, viewportHeight - tooltipRect.height));
        left = Math.max(0, Math.min(left, viewportWidth - tooltipRect.width));
      }
      
      // Set position
      this._tooltipElement.style.top = `${top + window.scrollY}px`;
      this._tooltipElement.style.left = `${left + window.scrollX}px`;
    }
    
    // Utility methods
    _generateId() {
      return Math.random().toString(36).substring(2, 10);
    }
    
    // Public API methods
    static create(element, options = {}) {
      const tooltip = new Tooltip(options);
      tooltip._attachToElement(element, options);
      return tooltip;
    }
    
    static initAll(options = {}) {
      return new Tooltip({
        ...options,
        dataAttributes: true
      });
    }
    
    destroy() {
      // Remove tooltip element if it exists
      if (this._tooltipElement && this._tooltipElement.parentNode) {
        this._tooltipElement.parentNode.removeChild(this._tooltipElement);
      }
      
      // Remove event listeners
      if (this.config.hideOnScroll) {
        window.removeEventListener('scroll', this._handleScroll);
      }
      
      // Clear timeouts
      clearTimeout(this._showTimeout);
      clearTimeout(this._hideTimeout);
      
    }
  }
  