import DOM from "./dom.js";
import QueryHelper from "./query-helper.js";


export default class DropdownSelect {
    constructor({
        element,
        data,
        type = "single",
        placeholder = "Select",
        preselected = [],
        searchable = false,
        key = "label",
        value = "value",
        style = null,
        isClearable = false,
        permissions = true,
        prefetch = null
    }) {
        this._element = element;
        this._key = key;
        this._value = value;
        this._data = data ? this._normalizeData(data) : [];
        this._type = type;
        this._placeholder = placeholder;
        this._searchable = searchable;
        this._style = style;
        this._isClearable = isClearable;
        this._permissions = permissions;
        this._dom = new DOM();
        this._queryHelper = new QueryHelper();
        this._prefetch = prefetch;
        this._currentFocus = null;

        if(this._style){
            this._placeholder = `${this._placeholder}`;
        }

        // Check if prefetch parameter exists in URL and use it for preselection
        if (prefetch && this._queryHelper._has(prefetch)) {
            const prefetchValue = this._queryHelper._get(prefetch);
            if (prefetchValue) {
                // Handle comma-separated values for multiple selection
                preselected = prefetchValue.includes(',') ? 
                    prefetchValue.split(',').map(val => val.trim()) : 
                    [prefetchValue];
            }
        }

        // Set preselected values
        this._selected = new Set(
            preselected && preselected.length > 0 && preselected[0] !== null
                ? preselected.flatMap(item => {
                    if (typeof item === 'string' && item.includes(',')) {
                        return item.split(',').map(val => val.trim());
                    }
                    return item;
                  })
                : []
        );

        // If prefetch is enabled and we have preselected values, update URL
        if (prefetch && this._selected.size > 0) {
            const selectedValues = Array.from(this._selected);
            if (this._type === "single") {
                window.history.pushState({}, '', this._queryHelper._add(this._prefetch, selectedValues[0])._toString());
            } else {
                window.history.pushState({}, '', this._queryHelper._add(this._prefetch, selectedValues.join(','))._toString());
            }
        }

        this._highlightedIndex = 0;
        this._allOptionEls = [];
        this._eventListeners = {};

        this._prefix = "";
        this._staticClass = {
            container: `${this._prefix}-dr-c`,
            menu: `${this._prefix}dropdown-content`,
            search: `${this._prefix}-dr-se`,
            group: `${this._prefix}-dr-g`,
            option: `${this._prefix}dropdown-item`,
        }
        this._render();
        
        // Dispatch an init event after rendering is complete
        setTimeout(() => {
            const initEvent = new CustomEvent('init', {
                detail: {
                    selected: Array.from(this._selected),
                    type: this._type,
                    element: this._element,
                    prefetch: this._prefetch
                }
            });
            this._element.dispatchEvent(initEvent);
        }, 0);
    }

    static currentOpenInstance = null;
    static globalClickListener = null;

    _render() {
        if(this._style === "picker"){
            this._dom.addClass(this._element, `${this._staticClass.container} f_input arrow_down`);
        } else {
            this._dom.addClass(this._element, `${this._staticClass.container} f_input arrow_down`);
        }

        // Make the element focusable
        this._dom.setAttr(this._element, 'tabindex', '0');

        // Set value directly on the element
        if (this._selected.size > 0) {
            this._dom.setAttr(this._element, 'value', Array.from(this._selected).join(','));
        }
        
        this._updateSelectedText();
        if(!this._permissions){
            return;
        }
        
        this._element.onclick = (e) => this._toggleMenu(e);
        document.addEventListener("keydown", (e) => this._handleKeydown(e));
    }

    _toggleMenu(e) {
        if (!this.menu) {
            if (DropdownSelect.currentOpenInstance) {
                DropdownSelect.currentOpenInstance._closeMenu();
            }

            this._createMenu();
            DropdownSelect.currentOpenInstance = this;

            if (this._style === "picker") {
                //this.menu.classList.add("fe");
                this._dom.addClass(this.menu, "fe");
                setTimeout(() => {
                    //this.menu.classList.add("fee");
                    this._dom.addClass(this.menu, "fee");
                }, 100);
            }

            if (!DropdownSelect.globalClickListener) {
                DropdownSelect.globalClickListener = (e) => {
                    const instance = DropdownSelect.currentOpenInstance;
                    if (
                        instance &&
                        instance.menu &&
                        !instance._element.contains(e.target) &&
                        !instance.menu.contains(e.target)
                    ) {
                        instance._closeMenu();
                    }
                };
                document.addEventListener("click", DropdownSelect.globalClickListener);
            }
        } else {
            this._closeMenu();
        }
    }

    _closeMenu() {
        if (this.menu) {
            if (this._style === "picker") {
                this._dom.removeClass(this.menu, "fee");
                setTimeout(() => {
                    this.menu.remove();
                    this.menu = null;
                    if (DropdownSelect.currentOpenInstance === this) {
                        DropdownSelect.currentOpenInstance = null;
                    }
                    // Focus back on the main element
                    this._element.focus();
                }, 100);
            } else {
                this.menu.remove();
                this.menu = null;
                if (DropdownSelect.currentOpenInstance === this) {
                    DropdownSelect.currentOpenInstance = null;
                }
                // Focus back on the main element
                this._element.focus();
            }
        }
    }

    _createMenu() {
        this.menu = this._dom.create({
            className: this._staticClass.menu,
        });
        
        if (this._searchable) {
            const searchInput = this._dom.create({
                tag: "input",
                className: this._staticClass.search,
                attributes: {
                    placeholder: "Search...",
                    autocomplete: "off"
                }
            });

            searchInput.addEventListener("input", (e) => {
                this._filterOptions(e.target.value.toLowerCase());
            });

            const searchInputWrapper = this._dom.create({});
            
            this._dom.append(searchInputWrapper, searchInput);
            this._dom.append(this.menu, searchInputWrapper);
        }

        this._optionContainer = this._dom.create({});
        this._dom.append(this.menu, this._optionContainer);

        this._dom.append(document.body, this.menu);
        this._positionMenu();

        this._buildOptions(this._data);
        
        // After building options, scroll to the highlighted option
        if (this._currentFocus) {
            setTimeout(() => {
                this._scrollToHighlighted();
            }, 0);
        }
    }

    _positionMenu() {
        const rect = this._element.getBoundingClientRect();
        this._dom.style(this.menu, {
            position: 'absolute',
            top: `${rect.bottom + window.scrollY}px`,
            left: `${rect.left + window.scrollX}px`,
            width: `${rect.width}px`,
            zIndex: '999999999',
        });
        // this._dom.style(this.menu, {
        //     position: 'absolute',
        //     top: `${rect.bottom + window.scrollY}px`,
        //     left: `${rect.left + window.scrollX}px`,
        //     width: `${rect.width}px`,
        //     zIndex: '999999999',
        // });
    }

    _buildOptions(data) {
        this._optionContainer.innerHTML = "";
        this._allOptionEls = [];
        this._highlightedIndex = 0;
        this._currentFocus = null;
        
        // Track if we've found a selected option to highlight
        let selectedOptionFound = false;

        data.forEach((option, index) => {
            const optionEl = this._dom.create({
                className: this._staticClass.option,
                attributes: {
                    tabIndex: 0
                }
            });

            if (this._selected.has(option.value)) {
                this._dom.addClass(optionEl, "active");
                // Set this as the highlighted option
                this._highlightedIndex = index;
                selectedOptionFound = true;
            }

            const label = document.createElement("span");
            label.append(option.label);
            optionEl.appendChild(label);

            optionEl.onclick = (e) => {
                e.stopPropagation();
                this._toggleOption(option);
            };

            this._optionContainer.appendChild(optionEl);
            this._allOptionEls.push(optionEl);
        });

        // Highlight either the selected option or the first option
        if (this._allOptionEls.length > 0) {
            this._focusOption(this._allOptionEls[this._highlightedIndex]);
        }

        this._updateSelectedText();
    }

    _toggleOption(option) {
        if (this._type === "single") this._selected.clear();

        if (this._selected.has(option.value)) {
            this._selected.delete(option.value);
        } else {
            this._selected.add(option.value);
        }

        this._buildOptions(this._data);
        this._updateSelectedValue();

        if (this._type === "single") {
            this._closeMenu();
        }
    }

    _filterOptions(query) {
        this._optionContainer.querySelectorAll(`.${this._staticClass.option}`).forEach((el) => {
            const label = el.innerText.toLowerCase();
            el.style.display = label.includes(query) ? "flex" : "none";
        });
    }

    _updateSelectedText() {
        // Update the element's text content directly
        this._element.innerHTML = "";

        if (this._selected.size === 0) {
            this._element.innerText = this._placeholder;
            return;
        }

        const selectedItems = [];

        this._data.forEach((item) => {
            if (this._selected.has(item.value)) {
                selectedItems.push({
                    label: item.label,
                    value: item.value
                });
            }
        });

        selectedItems.forEach(({ label, value }) => {
            const tag = this._dom.create({
                tag: "span",
                className: "selected-tag",
                attributes: {
                    "data-clearable": this._isClearable || false,
                    "data-picker": this._style === "picker",
                    "data-type": this._type
                }
            });
            
            // Create label span
            const labelSpan = document.createElement("span");
            labelSpan.innerText = label;

            if (this._permissions){
                labelSpan.onclick = (e) => {
                    e.stopPropagation(); // Stop propagation here
                    this._toggleMenu(e); // Explicitly toggle menu when clicking the label
                };
            }
            tag.appendChild(labelSpan);

            // Only add remove button if isClearable is true
            if (this._isClearable) {
                const removeBtn = this._dom.create({
                    tag: "span",
                    className: "remove-tag",
                    inner: "×"
                });

                removeBtn.onclick = (e) => {
                    e.stopPropagation();
                    this._selected.delete(value);
                    this._updateSelectedText(); // Update the UI directly
                    this._updateSelectedValue(); // Update URL parameter
                };
                tag.appendChild(removeBtn);
            }

            this._element.appendChild(tag);
        });
    }

    _handleKeydown(e) {
        // Toggle dropdown when pressing Enter or Space on the main element
        if ((e.key === 'Enter' || e.key === ' ') && e.target === this._element) {
            e.preventDefault();
            this._toggleMenu(e);
        }
        // Change value with arrow keys when dropdown is closed but element is focused (single type only)
        else if (!this.menu && e.target === this._element && 
                 (e.key === 'ArrowDown' || e.key === 'ArrowUp')) {
            e.preventDefault();
            if(this._type === "single"){
                this._changeValueWithArrowKeys(e.key);
            }else{
                this._toggleMenu(e);
            }
        }
        // Handle keyboard navigation when menu is open
        else if (this.menu) {
            this._handleKeyboardNavigation(e);
        }
    }

    _changeValueWithArrowKeys(key) {
        // Get current selected index or start at -1 if nothing selected
        let currentIndex = -1;
        const selectedValue = Array.from(this._selected)[0];
        
        if (selectedValue) {
            currentIndex = this._data.findIndex(item => item.value === selectedValue);
        }
        
        // Calculate new index based on arrow key
        let newIndex;
        if (key === 'ArrowDown') {
            newIndex = (currentIndex + 1) % this._data.length;
        } else { // ArrowUp
            newIndex = (currentIndex - 1 + this._data.length) % this._data.length;
        }
        
        // Select the new option
        const newOption = this._data[newIndex];
        
        // Clear previous selection (we know this is single type)
        this._selected.clear();
        
        // Add new selection
        this._selected.add(newOption.value);
        
        // Update UI and trigger change event
        this._updateSelectedText();
        this._updateSelectedValue();
    }

    _handleKeyboardNavigation(e) {
        if (!this.menu) return;
        
        const visibleOptions = this._allOptionEls.filter(el => 
            el.style.display !== 'none'
        );
        
        if (visibleOptions.length === 0) return;
        
        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                this._highlightedIndex = 
                    (this._highlightedIndex + 1) % visibleOptions.length;
                this._focusOption(visibleOptions[this._highlightedIndex]);
                break;
                
            case 'ArrowUp':
                e.preventDefault();
                this._highlightedIndex = 
                    (this._highlightedIndex - 1 + visibleOptions.length) % visibleOptions.length;
                this._focusOption(visibleOptions[this._highlightedIndex]);
                break;
                
            case 'Enter':
                e.preventDefault();
                if (this._currentFocus) {
                    this._currentFocus.click();
                }
                break;
                
            case 'Escape':
                e.preventDefault();
                this._closeMenu();
                break;
                
            case 'Tab':
                    this._closeMenu();
                break;
        }
    }

    _focusOption(option) {
        // Remove highlight from all options
        this._allOptionEls.forEach(el => {
            this._dom.removeClass(el, "highlighted");
        });
        
        // Add highlight to current option
        if (option) {
            this._dom.addClass(option, "highlighted");
            this._currentFocus = option;
            
            // Set actual keyboard focus
            option.focus();
            
            // Scroll into view if needed
            const container = this._optionContainer;
            const optionTop = option.offsetTop;
            const optionBottom = optionTop + option.offsetHeight;
            
            if (optionTop < container.scrollTop) {
                container.scrollTop = optionTop;
            } else if (optionBottom > container.scrollTop + container.clientHeight) {
                container.scrollTop = optionBottom - container.clientHeight;
            }
        }
    }

    _updateSelectedValue() {
        if (this._type === "single") {
            const selectedValues = Array.from(this._selected);
            this._element.setAttribute('value', selectedValues.length > 0 ? selectedValues[0] : '');
        } else {
            this._element.setAttribute('value', Array.from(this._selected).join(','));
        }

        // Handle prefetch parameter in URL if provided
        if (this._prefetch) {
            const selectedValues = Array.from(this._selected);
            if (selectedValues.length > 0) {
                // Add the prefetch parameter to URL
                if (this._type === "single") {
                    window.history.pushState({}, '', this._queryHelper._add(this._prefetch, selectedValues[0])._toString());
                } else {
                    // For multiple selection, join values with comma
                    window.history.pushState({}, '', this._queryHelper._add(this._prefetch, selectedValues.join(','))._toString());
                }
            } else {
                // Remove the prefetch parameter from URL if no selection
                if (this._queryHelper._has(this._prefetch)) {
                    window.history.pushState({}, '', this._queryHelper._remove(this._prefetch)._toString());
                }
            }
        }

        // Dispatch a change event
        const event = new CustomEvent('change', {
            detail: Array.from(this._selected)
        });
        this._element.dispatchEvent(event);
    }
    
    _scrollToHighlighted() {
        if (!this._currentFocus) return;
        
        const container = this._optionContainer;
        const option = this._currentFocus;
        
        const optionTop = option.offsetTop;
        const optionBottom = optionTop + option.offsetHeight;
        
        if (optionTop < container.scrollTop) {
            container.scrollTop = optionTop;
        } else if (optionBottom > container.scrollTop + container.clientHeight) {
            container.scrollTop = optionBottom - container.clientHeight;
        }
    }

    _normalizeData(data) {
        
        // Check if data is an array of strings
    if (Array.isArray(data) && data.length > 0 && typeof data[0] === 'string') {
        // Convert array of strings to dropdown options
        return data.map(item => ({
            label: item,
            value: item
        }));
    }
    
    // Handle regular array of objects
    return data.map(item => ({
        label: item[this._key] || item.label,
        value: item[this._value] || item.value,
        imageUrl: item.imageUrl || null
    }));
    }

}


window.DropdownSelect = DropdownSelect;
