import { assignees, permissions, priority, status } from "./env.js";

export default class State{
    constructor(endpoint, devMode) {
        this.endpoint = endpoint;
        this.devMode = devMode;

        this.stage = "init";
        this.project = null;
        this.user = null;

        this.assignees = null;
        this.priority = null;
        this.status = null;

        this.tasks = null;
        this.mousePos = {x:100, y:100};

        this.marker = null;
        this.explorer = null;

        this.permissions = permissions;


        this.setState("priority", priority , 'env');
        this.setState("status", status , 'env' );

        if (this.devMode) {
            this.setState("assignees", assignees);
        }
    }

    setState(option, value , from = null) {
        const str = from
            ? `%cState update from %c${from}%c: %c${option}`
            : `%cState update: %c${option}`;

            // console.groupCollapsed(
            // str,
            // "color: inherit; font-weight: 400;",
            // "color: green; font-weight: 700;",  // from
            // "color: inherit",          // colon
            // "color: blue; font-weight: 700;"    // option
            // );

        if (this.hasOwnProperty(option)) {
            this[option] = value;
            if(typeof value === "object"){
                //console.table(value);
            }else{
                //console.log(value);
            }

        } else {
            console.warn(`Cannot set undefined property: ${option}`);
        }
        console.groupEnd();
    }


    getTaskById(id) {
        if(this.tasks === null){
            return false;
        }

        const task = this.tasks.find(task => task.id === id);
        if (task) {
            return task;
        }else{
            return false;
        }
    }

    getTotalTasks(){
        if(this.tasks === null){
            return 0;
        }
        return this.tasks.length;
    }

    addTask(task){
        if(this.tasks === null){
            this.tasks = [];
            this.tasks.push(task);
            return 1;
        }
        this.tasks.push(task);
        return this.tasks.length;
    }

    updateTask(task){
        const index = this.tasks.findIndex(t => t.id === task.id);
        this.tasks[index] = task;
    }

    setStage(stage,from = null){
        const stages = {
            init: "init",           
            overlay: "overlay",     
            form_create: "form_create",  
            form_created: "form_created",
            form_view: "form_view",      
            form_edit: "form_edit",

            /* */
            marker_click: "marker_click",
            marker_double_click: "marker_double_click",
        }
        if(!stages[stage]){
            console.error(`Invalid stage: ${stage} from ${from}` );
            return;
        }
        if(from){
            console.log(`Stage set from %c${from}%c to %c${stage}`, 
                'color: blue;', // Blue for `from`
                '',             // Default styling for 'to'
                'color: green;' // Green for `stage`
              );
        }else{
            console.log(`Stage set to: ${stage}`);
        }
        this.stage = stage;
    }

    getStage(){
        return this.stage;
    }

    getUserPermissions(task = null){
        const isPermission = this.permissions[this.user.role];
        const role = this.user.role;
        if(task == null){
            return {isPermission, role};    
        }else{
            const isSameUser = this.user.id === task.created_by;
            return {isPermission, isSameUser, role};
        }
    }

    getUserById(id){
        // want to return the user object from the assignees array
        const user = this.assignees.find(user => user.user_id === id);
        if (user) {
            return user;
        }else{
            return false;
        }
    }


    
}
