export default class Storage {
    constructor() {
        this.storage = window.localStorage;
    }

    setItem(key, value) {
        this.storage.setItem(key, JSON.stringify(value));
    }

    getItem(key) {
        const item = this.storage.getItem(key);
        return item ? JSON.parse(item) : null;
    }

    set(key, value) {
        this.setItem(key, value);
    }

    get(key) {
        return this.getItem(key);
    }

    removeItem(key) {
        this.storage.removeItem(key);
    }

    clear() {
        this.storage.clear();
    }

    /* store tasks list in local storage */
    storeTasks(tasks) {
        this.setItem('tasks', tasks);
    }
    getTasks() {
        // first check if tasks are already stored in local storage
        if (this.getItem('tasks')) {
            return this.getItem('tasks');
        }else{
            return false;
        }
    }
    pushTask(task) {
        const tasks = this.getItem('tasks');
        if(!tasks){
            this.storeTasks([task]);
        }else{
            tasks.push(task);
            this.setItem('tasks', tasks);
        }
    }
    updateTask(task) {
        const tasks = this.getItem('tasks');
        const index = tasks.findIndex(t => t.id === task.id);
        tasks[index] = task;
        this.setItem('tasks', tasks);
    }
    deleteAllTasks() {
        this.removeItem('tasks');
    }

    /* set cookie */
    setCookie(name, value, days) {
        const expires = new Date();
        expires.setTime(expires.getTime() + days * 24 * 60 * 60 * 1000);
        document.cookie = `${name}=${value};expires=${expires.toUTCString()};path=/`;
    }

    getCookie(name) {
        const cookie = document.cookie.split(';').find(cookie => cookie.trim().startsWith(`${name}=`));
        return cookie ? cookie.split('=')[1] : null;
    }

    // store user in cookie
    storeUser(user) {
        this.setCookie('user', JSON.stringify(user), 30);
    }
    getUser() {
        const user = this.getCookie('user');
        return user ? JSON.parse(user) : false;
    }
    

    // store project in cookie
    storeProject(project) {
        this.setCookie('project', JSON.stringify(project), 30);
    }
    getProject() {
        const project = this.getCookie('project');
        return project ? JSON.parse(project) : false;
    }

    // store assignees in cookie
    storeAssignees(assignees) {
        this.setCookie('assignees', JSON.stringify(assignees), 30);
    }
    getAssignees() {
        const assignees = this.getCookie('assignees');
        return assignees ? JSON.parse(assignees) : false;
    }
}